from flask import Flask, session, request, jsonify
import redis
import functools
import time
import json

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

@app.before_request
def check_session():
    if 'user_id' in session:
        # Store session in Redis
        redis_client.setex(f"session:{session['user_id']}", 3600, json.dumps(session))

@app.route('/login', methods=['POST'])
def login():
    user_id = request.json.get('user_id')
    if user_id:
        session['user_id'] = user_id
        # Store session in Redis
        redis_client.setex(f"session:{user_id}", 3600, json.dumps(session))
        return jsonify({"status": "logged_in"})
    return jsonify({"status": "failed"}), 401

@app.route('/logout')
def logout():
    user_id = session.get('user_id')
    if user_id:
        redis_client.delete(f"session:{user_id}")
    session.clear()
    return jsonify({"status": "logged_out"})

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, json.dumps(result))
            return result
        return wrapper
    return decorator

@cache_result(expiration=600)
def expensive_database_query(user_id):
    # Simulate expensive database operation
    time.sleep(2)
    return {"user_id": user_id, "data": f"expensive_data_for_user_{user_id}"}

@app.route('/user/<int:user_id>')
def get_user_data(user_id):
    # This will be cached for 10 minutes
    data = expensive_database_query(user_id)
    return jsonify(data)

@app.route('/session/<user_id>')
def get_session(user_id):
    session_data = redis_client.get(f"session:{user_id}")
    if session_data:
        return jsonify(json.loads(session_data))
    return jsonify({"error": "Session not found"}), 404

if __name__ == '__main__':
    app.run(debug=False)